#include <stdio.h>
#include <stdlib.h>

#define RADIX 255

static long range = 1;
static long fraction = 0;
static int cc[2000000];

static void normalize_before(void){
    while(range < RADIX){
        long digit = fraction / RADIX;
        putchar((unsigned char)((digit + 1) & 0xFF));
        fraction = (fraction - digit * RADIX) * RADIX;
        range *= RADIX;
    }
}
static void put_bit(int ctx, int bit){
    normalize_before();
    int idx = ctx * 2;
    int c0 = cc[idx], c1 = cc[idx + 1];
    long split = range * (c0 + 1) / (c0 + c1 + 2);
    if(bit == 0){
        range = split;
    }else{
        fraction += split;
        range -= split;
    }
    cc[idx + bit]++;
    fprintf(stderr, "ENC ctx=%d bit=%d split=%ld fraction=%ld range=%ld c0=%d c1=%d\n", ctx, bit, split, fraction, range, c0, c1);
}
static void encode_integer(int start, int ctx, int value){
    long result = (long)value + (1L << start);
    int k = 0;
    while((1L << (k + 1)) <= result) k++;
    int ctx2 = ctx * 99;
    fprintf(stderr, "ENC value=%d result=%ld k=%d start=%d\n", value, result, k, start);
    for(int t = start + 1; t <= start + k; t++) put_bit(t + ctx2, 0);
    put_bit(start + k + 1 + ctx2, 1);
    for(int i = k - 1; i >= 0; i--) put_bit(ctx, (int)((result >> i) & 1));
}
static void finish(void){
    normalize_before();
    for(int i = 0; i < 8; i++){
        long digit = fraction / RADIX;
        putchar((unsigned char)((digit + 1) & 0xFF));
        fraction = (fraction - digit * RADIX) * RADIX;
        range *= RADIX;
    }
}
int main(void){
    encode_integer(9, 0, 7);
    finish();
    return 0;
}
